#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a[26] = {0};
        for (int i = 0; i < 26; i++) {
            scanf("%d", &a[i]);
        }
        char result[n + 1];
        result[n] = '\0';
        int pos = 0;
        while (pos < n) {
            int minLetter = -1;
            for (int i = 0; i < 26; i++) {
                if (a[i] > 0 && (pos + 1) % (i + 1) == 0) {
                    if (minLetter == -1 || i < minLetter) {
                        minLetter = i;
                    }
                }
            }
            if (minLetter == -1) {
                printf("#rekt\n");
                break;
            }
            result[pos] = 'a' + minLetter;
            a[minLetter]--;
            pos++;
        }
        if (pos == n) {
            printf("%s\n", result);
        }
    }
    return 0;
}

